// Extract source_signal_ids from the topic and build the query URL
// Also normalize the topic data for downstream nodes

const topic = $input.first().json;

if (!topic || !topic.id) {
  throw new Error('Topic not found for the given topic_id');
}

const signalIds = topic.source_signal_ids || [];
const signalIdsString = signalIds.join(',');

return [{
  json: {
    topic: topic,
    signal_ids_query: signalIdsString,
    has_signals: signalIds.length > 0
  }
}];

// Assemble the full context package for Claude content generation
// Combines topic, research signals, top hooks, and calendar slot
// Builds the prompt following the PROMPT.md template

const prepData = $('Prepare Signal Fetch').first().json;
const topic = prepData.topic;

// Get signals -- may be array of items or a single empty array response
const signalsRaw = $('Fetch Source Signals').all();
let signals = [];
for (const item of signalsRaw) {
  if (item.json && item.json.title) {
    signals.push(item.json);
  } else if (Array.isArray(item.json)) {
    signals = signals.concat(item.json.filter(s => s && s.title));
  }
}

// Get top hooks
const hooksRaw = $('Fetch Top Hooks').all();
let topHooks = [];
for (const item of hooksRaw) {
  if (item.json && item.json.hook_text) {
    topHooks.push(item.json);
  } else if (Array.isArray(item.json)) {
    topHooks = topHooks.concat(item.json.filter(h => h && h.hook_text));
  }
}

// Get calendar slot (may be empty array if no open slots)
const calendarRaw = $('Find Calendar Slot').all();
let calendarSlot = null;
for (const item of calendarRaw) {
  if (item.json && item.json.id) {
    calendarSlot = item.json;
    break;
  } else if (Array.isArray(item.json) && item.json.length > 0 && item.json[0].id) {
    calendarSlot = item.json[0];
    break;
  }
}

// Determine series and pillar
const series = topic.recommended_series || (calendarSlot ? calendarSlot.series : 'flex');
const pillar = calendarSlot ? (calendarSlot.pillar || 'legacy_future') : 'legacy_future';

// Build research context (truncate body_text to 500 chars per signal)
const researchContext = signals.map(s =>
  s.title + ' [' + (s.source || 'unknown') + ']: ' + (s.body_text || '').substring(0, 500)
).join('\n\n');

// Build hook patterns
const hookPatterns = topHooks.map(h =>
  '- [' + (h.hook_category || 'unknown') + '] ' + h.hook_text
).join('\n');

// Pillar-specific framing instructions
let pillarFraming = '';
if (pillar === 'legacy_future') {
  pillarFraming = 'PILLAR FRAMING: Legacy & Future -- Contrast IAML\'s institutional track record (est. 1979, 80,000+ professionals trained) with what Agentic AI now makes possible. Frame as business evolution, not personal history.';
} else if (pillar === 'building_in_public') {
  pillarFraming = 'PILLAR FRAMING: Building in Public -- Include a specific technical detail: a code snippet, workflow logic, or automation result. Show the build, not just the theory.';
} else if (pillar === 'partnered_authority') {
  pillarFraming = 'PILLAR FRAMING: Partnered Authority -- Reference IAML faculty/attorney expertise. Show the translation: legal knowledge turned into an AI guardrail or automated rule.';
}

// Build the full prompt
const systemPrompt = 'You are writing a LinkedIn post for Mike Van Horn, "The HR Technologist." Mike runs IAML (est. 1979), a 45-year employment law training company, and has genuine expertise in AI and automation -- he builds HR compliance tools using Claude Code and multi-agent systems. He is NOT an attorney or HR practitioner. His unique position: access to deep-domain expertise (IAML\'s practicing attorneys) + technical rapid prototyping capability.\n\nBRAND VOICE: Innovative, grounded, technically curious, and radically focused on efficiency. "Smart friend at a conference who happens to be in the trenches building AI tools." Observer and builder, never prescriber.';

const userPrompt = `TOPIC: ${topic.topic_title}
ANGLE: ${topic.angle || 'No specific angle provided'}
FORMAT: ${topic.recommended_format || 'text'}
SERIES: ${series}
PILLAR: ${pillar}
KEY DATA POINTS: ${JSON.stringify(topic.key_data_points || [])}

RESEARCH CONTEXT:
${researchContext || 'No research signals available'}

PRODUCT PHASE: Phase 1 (Current): The Ingestion Engine -- Building an agent that takes messy HR policy documents and outputs structured AI logic.

HOOK PATTERNS TO CONSIDER:
${hookPatterns || 'No hook library data available'}

${pillarFraming}

AEO (AI ENGINE OPTIMIZATION) -- Weave these terms naturally where relevant:
- "Agentic RAG" (when discussing AI that retrieves and reasons over documents)
- "Compliance Guardrails" (when discussing AI safety/rules for HR)
- "Multi-Agent Orchestration" (when discussing automated workflows)
- "HR Agentic Systems" (when discussing AI tools for HR operations)
Do NOT force these terms. Use them only when they fit the topic naturally.

RULES:
- Target 1,800-2,000 characters for the full post text
- Generate 3 hook variations: data/statistic (Hook A), contrarian (Hook B), observation (Hook C)
- First 2 lines MUST be a punchy hook, followed by 2 lines of white space
- Break text every 2-3 lines for mobile (short, scannable paragraphs)
- End with a "binary" or "low-friction" question to drive comment volume
- NO links in post body (put in first comment)
- NO emojis in body text
- Maximum 3-5 hashtags at the very end
- NEVER give legal advice
- NEVER use: "delve," "landscape," "in today's rapidly evolving," "it's important to note," "I'm excited to share"
- NEVER use corporate jargon: "leverage," "synergize," "paradigm shift"
- Use concrete specifics, not vague claims
- One idea per post -- go deep, not wide

Also generate:
- A first comment (link to relevant resource, extended thought, or seeding question)
- If format is carousel: an outline of 5-8 slides with title and key point per slide

Respond with ONLY valid JSON (no markdown fences, no commentary). Use this exact structure:
{
  "hook_a": { "text": "data/statistic hook text", "category": "data" },
  "hook_b": { "text": "contrarian hook text", "category": "contrarian" },
  "hook_c": { "text": "observation hook text", "category": "observation" },
  "full_text": "complete post text using Hook A, 1800-2000 characters, with hashtags at end",
  "first_comment_text": "first comment text with links and extended context",
  "hashtags": ["hashtag1", "hashtag2", "hashtag3"],
  "series": "${series}",
  "pillar": "${pillar}"
}`;

return [{
  json: {
    system_prompt: systemPrompt,
    user_prompt: userPrompt,
    topic: topic,
    calendar_slot: calendarSlot,
    series: series,
    pillar: pillar
  }
}];

// Parse the Claude content generation response
// Extract hooks, full_text, first_comment, hashtags
// Build hook_variations JSONB array
// Handle parse failures gracefully

const claudeResponse = $input.first().json;
const contextData = $('Assemble Context Package').first().json;
const topic = contextData.topic;

let result;
let parseFailed = false;
let rawResponse = '';

try {
  rawResponse = claudeResponse.content?.[0]?.text || '{}';
  const cleaned = rawResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  result = JSON.parse(cleaned);
} catch (e) {
  parseFailed = true;
  result = {
    hook_a: { text: topic.hook_suggestion || topic.topic_title, category: 'data' },
    hook_b: { text: topic.topic_title, category: 'contrarian' },
    hook_c: { text: topic.topic_title, category: 'observation' },
    full_text: 'GENERATION FAILED: Parse error. Raw response saved in generation_instructions for debugging.',
    first_comment_text: '',
    hashtags: [],
    series: contextData.series,
    pillar: contextData.pillar
  };
}

// Check for stop_reason = max_tokens (truncated response)
const stopReason = claudeResponse.stop_reason || '';
if (stopReason === 'max_tokens' && !parseFailed) {
  parseFailed = true;
  result.full_text = result.full_text || 'GENERATION TRUNCATED: Claude hit max_tokens limit. Retry with shorter context.';
}

// Build hook_variations JSONB array
const hookVariations = [
  { text: result.hook_a?.text || '', category: result.hook_a?.category || 'data', variation: 'A' },
  { text: result.hook_b?.text || '', category: result.hook_b?.category || 'contrarian', variation: 'B' },
  { text: result.hook_c?.text || '', category: result.hook_c?.category || 'observation', variation: 'C' }
];

// Default selected hook is Hook A (data variation)
const selectedHook = hookVariations[0];

// Build the post insert payload
const postPayload = {
  topic_id: topic.id,
  hook_text: selectedHook.text,
  hook_category: selectedHook.category,
  hook_variation: 'A',
  hook_variations: hookVariations,
  full_text: result.full_text || '',
  first_comment_text: result.first_comment_text || '',
  format: topic.recommended_format || 'text',
  series: result.series || contextData.series,
  pillar: result.pillar || contextData.pillar,
  hashtags: result.hashtags || [],
  status: 'draft',
  generation_status: parseFailed ? 'failed' : 'completed',
  generation_instructions: parseFailed ? ('Parse error. Raw response: ' + rawResponse.substring(0, 2000)) : null
};

return [{
  json: {
    post_payload: postPayload,
    topic: topic,
    calendar_slot: contextData.calendar_slot,
    parse_failed: parseFailed
  }
}];

// Extract the inserted post ID and prepare calendar slot update
// Handle both array and object responses from Supabase

const insertResponse = $input.first().json;
const prevData = $('Parse Generation Response').first().json;
const calendarSlot = prevData.calendar_slot;
const topic = prevData.topic;

// Supabase return=representation returns array or single object
let postId;
if (Array.isArray(insertResponse)) {
  postId = insertResponse[0]?.id;
} else {
  postId = insertResponse.id;
}

if (!postId) {
  // Try to extract from the response body directly
  postId = insertResponse?.id || null;
}

return [{
  json: {
    post_id: postId,
    topic_id: topic.id,
    topic_title: topic.topic_title,
    calendar_slot: calendarSlot,
    has_calendar_slot: calendarSlot !== null && calendarSlot !== undefined,
    series: prevData.post_payload?.series || 'flex',
    pillar: prevData.post_payload?.pillar || 'legacy_future',
    parse_failed: prevData.parse_failed
  }
}];

